import { cn } from '@/utils/cn';
import { cva, type VariantProps } from 'class-variance-authority';
import { Component, createEffect, createSignal, mergeProps, Show } from 'solid-js';
import type { SwitchProps } from './switch.types';

const variants = cva('', {
  variants: {
    size: {
      xs: 'h-4 w-7',
      sm: 'h-5 w-9',
      md: 'h-6 w-11',
      lg: 'h-7 w-14',
      xl: 'h-8 w-16',
    },
    color: {
      primary: 'bg-primary text-primary',
      secondary: 'bg-secondary text-secondary',
      accent: 'bg-accent text-accent',
      neutral: 'bg-neutral text-neutral',
      info: 'bg-info text-info',
      success: 'bg-success text-success',
      warning: 'bg-warning text-warning',
      error: 'bg-error text-error',
    },
  },
});

export type SwitchVariantProps = VariantProps<typeof variants>;

export const Switch: Component<SwitchProps> = props => {
  const p = mergeProps(
    {
      className: '',
      defaultChecked: false,
      disabled: false,
      loading: false,
      size: 'md' as const,
      color: 'primary' as const,
    },
    props,
  );

  const [internalChecked, setInternalChecked] = createSignal(p.defaultChecked);

  const isControlled = () => p.checked !== undefined;
  const checked = () => (isControlled() ? p.checked! : internalChecked());

  createEffect(function syncControlledChecked() {
    if (isControlled()) {
      setInternalChecked(p.checked!);
    }
  });

  const mergedDisabled = () => p.disabled || p.loading;

  const handleClick = (e: MouseEvent) => {
    if (mergedDisabled()) return;

    const newChecked = !checked();

    if (!isControlled()) {
      setInternalChecked(newChecked);
    }

    p.onClick?.(newChecked);
    p.onChange?.(newChecked);
  };

  return (
    <button
      type="button"
      role="switch"
      aria-checked={checked()}
      disabled={mergedDisabled()}
      class={cn(
        'sui_switch @container relative flex cursor-pointer items-center rounded-full border-2 border-transparent p-px',
        variants({ size: p.size, color: p.color }),
        'transition duration-400',
        !checked() && 'bg-gray-300',
        mergedDisabled() && 'cursor-not-allowed opacity-50',
        p.class?.root,
      )}
      onClick={handleClick}
    >
      <div
        class={cn(
          'sui_thumb aspect-square h-full rounded-full bg-white transition-transform duration-400 ease-in-out',

          checked() && 'translate-x-[calc(100cqw-100%)]',
        )}
      >
        <Show when={p.loading}>
          <span class="flex size-full animate-spin">
            <IconLoading />
          </span>
        </Show>
      </div>
    </button>
  );
};

const IconLoading = () => {
  return (
    <svg class="size-full" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
      <circle class="opacity-25" cx="12" cy="12" r="10" stroke="#ccc" stroke-width="4"></circle>
      <path
        class="opacity-90"
        fill="currentColor"
        d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
      ></path>
    </svg>
  );
};
